'use client';

import { useEffect, useRef, useState, type RefObject } from 'react';
import { useReducedMotion } from './use-reduced-motion';
import { DURATION, EASING, DISTANCE } from './tokens';

type AnimationPreset = 'fadeIn' | 'slideUp' | 'slideDown' | 'scaleIn';

interface EntranceAnimationOptions {
  /**
   * Animation preset to use
   * @default 'fadeIn'
   */
  preset?: AnimationPreset;

  /**
   * Delay before animation starts (ms)
   * @default 0
   */
  delay?: number;

  /**
   * Duration override (ms)
   * @default DURATION.normal (250ms)
   */
  duration?: number;

  /**
   * Whether to trigger animation on mount
   * @default true
   */
  animateOnMount?: boolean;
}

interface EntranceAnimationReturn<T extends HTMLElement> {
  /** Ref to attach to the animated element */
  ref: RefObject<T | null>;
  /** CSS styles to apply to the element */
  style: React.CSSProperties;
  /** Whether currently animating */
  isAnimating: boolean;
  /** Whether animation has completed */
  hasAnimated: boolean;
  /** Manually trigger the animation */
  triggerAnimation: () => void;
}

/**
 * Hook for entrance animations with reduced motion support.
 *
 * Provides CSS-based animations that respect user preferences.
 *
 * @example
 * ```tsx
 * function Card() {
 *   const { ref, style, hasAnimated } = useEntranceAnimation<HTMLDivElement>({
 *     preset: 'slideUp',
 *     delay: 100,
 *   });
 *
 *   return (
 *     <div ref={ref} style={style}>
 *       {hasAnimated ? 'Visible!' : 'Animating...'}
 *     </div>
 *   );
 * }
 * ```
 */
export function useEntranceAnimation<T extends HTMLElement = HTMLDivElement>(
  options: EntranceAnimationOptions = {}
): EntranceAnimationReturn<T> {
  const {
    preset = 'fadeIn',
    delay = 0,
    duration = DURATION.normal,
    animateOnMount = true,
  } = options;

  const ref = useRef<T>(null);
  const [isAnimating, setIsAnimating] = useState(false);
  const [hasAnimated, setHasAnimated] = useState(false);
  const prefersReducedMotion = useReducedMotion();

  // Get initial CSS styles based on preset (before animation)
  const getInitialStyle = (): React.CSSProperties => {
    // If reduced motion or already animated, show final state
    if (prefersReducedMotion || hasAnimated) {
      return {
        opacity: 1,
        transform: 'none',
      };
    }

    // Initial hidden state
    switch (preset) {
      case 'fadeIn':
        return { opacity: 0 };
      case 'slideUp':
        return { opacity: 0, transform: `translateY(${DISTANCE.md}px)` };
      case 'slideDown':
        return { opacity: 0, transform: `translateY(-${DISTANCE.md}px)` };
      case 'scaleIn':
        return { opacity: 0, transform: 'scale(0.95)' };
      default:
        return { opacity: 0 };
    }
  };

  // Get animating CSS styles (with transitions)
  const getAnimatingStyle = (): React.CSSProperties => {
    return {
      opacity: 1,
      transform: 'translateY(0) scale(1)',
      transition: `opacity ${duration}ms ${EASING.out}, transform ${duration}ms ${EASING.out}`,
      transitionDelay: `${delay}ms`,
    };
  };

  // Trigger the animation
  const triggerAnimation = () => {
    // Skip animation if reduced motion is preferred
    if (prefersReducedMotion) {
      setHasAnimated(true);
      return;
    }

    setIsAnimating(true);

    // After animation completes, update state
    const totalDuration = duration + delay;
    setTimeout(() => {
      setIsAnimating(false);
      setHasAnimated(true);
    }, totalDuration);
  };

  // Auto-trigger on mount if enabled
  useEffect(() => {
    if (animateOnMount && !hasAnimated) {
      // Small delay to ensure DOM is ready
      const timer = setTimeout(triggerAnimation, 10);
      return () => clearTimeout(timer);
    }
  }, [animateOnMount, hasAnimated, prefersReducedMotion, duration, delay]);

  return {
    ref,
    style: isAnimating ? getAnimatingStyle() : getInitialStyle(),
    isAnimating,
    hasAnimated,
    triggerAnimation,
  };
}
